alcLtobH <- exp(coef(mdl)["tobH"])
alcMtobL <- exp(coef(mdl)["alcM"])
alcMtobH <- exp(coef(mdl)["alcM"]) *
  exp(coef(mdl)["tobH"]) *
  exp(coef(mdl)["alcM:tobH"])
alcHtobL <- exp(coef(mdl)["alcH"])
alcHtobH <- exp(coef(mdl)["alcH"]) *
  exp(coef(mdl)["tobH"]) *
  exp(coef(mdl)["alcH:tobH"])
